import { useState, useEffect, useCallback } from 'react';
import attendanceService from '../services/attendanceService';

export const useAttendance = () => {
  const [todayAttendance, setTodayAttendance] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [actionLoading, setActionLoading] = useState(false);

  const fetchToday = useCallback(async () => {
    try {
      setLoading(true);
      const { data } = await attendanceService.getToday();
      setTodayAttendance(data.data.attendance);
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchToday(); }, [fetchToday]);

  const checkIn = async () => {
    setActionLoading(true);
    try {
      const { data } = await attendanceService.checkIn();
      setTodayAttendance(data.data.attendance);
      return { success: true };
    } catch (err) {
      return { success: false, message: err.message };
    } finally {
      setActionLoading(false);
    }
  };

  const checkOut = async () => {
    setActionLoading(true);
    try {
      const { data } = await attendanceService.checkOut();
      setTodayAttendance(data.data.attendance);
      return { success: true };
    } catch (err) {
      return { success: false, message: err.message };
    } finally {
      setActionLoading(false);
    }
  };

  return { todayAttendance, loading, error, actionLoading, checkIn, checkOut, refresh: fetchToday };
};

export const useAttendanceHistory = (params) => {
  const [attendances, setAttendances] = useState([]);
  const [pagination, setPagination] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetch = useCallback(async () => {
    try {
      setLoading(true);
      const { data } = await attendanceService.getMyHistory(params);
      setAttendances(data.data);
      setPagination(data.pagination || {});
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [JSON.stringify(params)]); // eslint-disable-line

  useEffect(() => { fetch(); }, [fetch]);
  return { attendances, pagination, loading, error, refresh: fetch };
};
